skinparam classStereotypeBorderColor #000000

class "DrawingObject" as DrawingObject {
    virtual void Draw()
}

class "Circle" as Circle {
    override void Draw()
}

class "Square" as Square {
    override void Draw()
}

class "Line" as Line {
    override void Draw()
}

class "Rectangle" as Rectangle {
    new void Draw()
}

DrawingObject <|-- Circle
DrawingObject <|-- Square
DrawingObject <|-- Line
Square <|-- Rectangle

